Here isa minimal web‑based editing app.

FILE: editor.html
```html
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Simple Web Editor</title>
<style>
  body {font-family: Arial, sans-serif; margin:0; padding:0; background:#f4f4f4; display:flex; flex-direction:column; height:100vh;}
  .toolbar {background:#333; color:#fff; padding:10px; display:flex; gap:5px;}
  .toolbar button {background:#555; color:#fff; border:none; padding:8px 12px; cursor:pointer; border-radius:4px;}
  .toolbar button:hover {background:#444;}
  #editor {flex:1; padding:10px; border:1px solid #ccc; background:#fff; overflow-y:auto;}
  #preview {padding:10px; background:#e9e9e9; margin-top:10px;}
</style>
</head>
<body>
<div class="toolbar">
  <button id="boldBtn"><b>B</b></button>
  <button id="italicBtn"><i>I</i></button>
  <button id="underlineBtn"><u>U</u></button>
  <button id="clearBtn">Clear</button>
  <button id="saveBtn">Save</button>
</div>
<div id="editor" contenteditable="true"></div>
<div id="preview"></div>

<script>
const editor = document.getElementById('editor');
const preview = document.getElementById('preview');
const saveBtn = document.getElementById('saveBtn');
const boldBtn = document.getElementById('boldBtn');
const italicBtn = document.getElementById('italicBtn');
const underlineBtn = document.getElementById('underlineBtn');
const clearBtn = document.getElementById('clearBtn');

// Apply formatting
boldBtn.onclick = () => document.execCommand('bold');
italicBtn.onclick = () => document.execCommand('italic');
underlineBtn.onclick = () => document.execCommand('underline');
clearBtn.onclick = () => document.execCommand('removeFormat');

// Save content
saveBtn.onclick = () => {
  const data = editor.innerHTML;
  localStorage.setItem('editedContent', data);
  alert('Content saved to browser storage.');
};

// Load saved content on start
window.addEventListener('DOMContentLoaded', () => {
  const saved = localStorage.getItem('editedContent');
  if (saved) {
    editor.innerHTML = saved;
  }
  updatePreview();
});

// Update preview pane
function updatePreview() {
  preview.innerHTML = editor.innerHTML;
}

// Observe content changes
editor.addEventListener('input', updatePreview);
</script>
</body>
</html>
```

